import json, sys
from datetime import datetime

data = json.load(sys.stdin)
feeds = data.get('feeds', [])

fields = {'field1': [], 'field2': [], 'field3': [], 'field4': []}

for f in feeds:
    for key in fields:
        val = f.get(key)
        if val is not None and val != '':
            try:
                fields[key].append(float(val))
            except:
                pass

for key, vals in fields.items():
    if vals:
        print(f'{key}: count={len(vals)}, avg={sum(vals)/len(vals):.2f}, min={min(vals):.2f}, max={max(vals):.2f}')
    else:
        print(f'{key}: count=0, avg=N/A, min=N/A, max=N/A')
